arguments.file_text:
@if (Visible)
{
    <div class="emoji-picker" @onclick:stopPropagation="true">
        @foreach (var emoji in _emojis)
        {
            <button class="emoji-option" @onclick="() => SelectEmoji(emoji)" title="@emoji">@emoji</button>
        }
    </div>
}

@code {
    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🔥"];

    [Parameter] public bool Visible { get; set; }
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    position: absolute;
    bottom: 100%;
    left: 0;
    z-index: 10;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #dee2e6;
    background: var(--bs-body-bg, #fff);
    align-items: flex-end;
}

.message-input textarea {
    resize: none;
    flex: 1;
    font-size: 0.9rem;
}

.send-btn {
    align-self: flex-end;
    white-space: nowrap;
}

.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-item.hovered {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #6c757d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #e9ecef;
    border: 1px solid #dee2e6;
    border-radius: 12px;
    padding: 1px 8px;
    font-size: 0.8rem;
    cursor: default;
}

.thread-link {
    font-size: 0.8rem;
    margin-top: 4px;
    text-decoration: none;
    color: #0d6efd;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.message-actions .btn {
    font-size: 0.8rem;
    padding: 2px 6px;
    line-height: 1;
}

.react-btn-wrapper {
    position: relative;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    background: none;
    border: none;
    padding: 10px 14px;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.15s;
    color: inherit;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.2);
    font-weight: 600;
}

.channel-header-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-size: 0.95rem;
    font-weight: 500;
    color: #fff;
}

.channel-item.active .channel-name {
    font-weight: 700;
}

.channel-desc {
    font-size: 0.75rem;
    color: rgba(255, 255, 255, 0.6);
    margin-top: 2px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.unread-badge {
    font-size: 0.7rem;
    min-width: 20px;
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2c2f33;
    color: #fff;
}

.channel-list-header {
    padding: 16px 14px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.channel-list-header h6 {
    margin: 0;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: rgba(255, 255, 255, 0.5);
}

.channel-list-items {
    flex: 1;
    overflow-y: auto;
    padding: 8px 6px;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    border-left: 1px solid #dee2e6;
    background: var(--bs-body-bg, #fff);
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #dee2e6;
}

.thread-header h6 {
    margin: 0;
    font-weight: 700;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    border-left: 3px solid #6c757d;
    margin: 0;
}

.quote-author {
    font-weight: 600;
    font-size: 0.85rem;
    margin-bottom: 2px;
}

.quote-content {
    font-size: 0.85rem;
    color: #495057;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using System.Collections.Generic

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h5># @Channel.Name</h5>
            <span class="channel-description">@Channel.Description</span>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="_scrollContainer">
            @if (_loadingMore)
            {
                <div class="text-center py-2">
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                </div>
            }
            @foreach (var msg in Messages)
            {
                <MessageItem Message="msg"
                             ThreadSummary="GetThreadSummary(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      OnSend="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p class="text-muted">Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    private ElementReference _scrollContainer;
    private bool _loadingMore;

    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.Find(t => t.RootMessageId == messageId);

    private async Task HandleScroll()
    {
        // The page component will handle pagination via the OnLoadMore callback.
        // A real implementation would check scrollTop via JS interop;
        // here we expose the callback for the parent to wire up.
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--bs-body-bg, #fff);
}

.message-area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

.message-area-header h5 {
    margin: 0;
    font-weight: 700;
}

.channel-description {
    font-size: 0.8rem;
    color: #6c757d;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
}

