{"path": "/tmp/sv-b70a52eda0bc469e8870322f5b3fb579/Components/Chat/MessageInput.razor", "file_text": "<div class="message-input">
    <textarea class="form-control" rows="2"
              placeholder="@Placeholder"
              @bind="_text"
              @onkeydown="HandleKeyDown" />
    <button class="btn btn-primary btn-sm send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonLabel
    </button>
</div>

@code {
    private string _text = string.Empty;

    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(_text)) return;
        var content = _text.Trim();
        _text = string.Empty;
        await OnSend.InvokeAsync(content);
    }
}
"}

