+++ b/tmp/sv-b70a52eda0bc469e8870322f5b3fb579/Components/Chat/MessageItem.razor
@@ -1,0 +1,82 @@
+<div class="message-item @(_hovered ? "hovered" : "")"
+     @onmouseenter="() => _hovered = true"
+     @onmouseleave="OnMouseLeave">
+    <div class="message-header">
+        <span class="message-author">@Message.Author</span>
+        <span class="message-time" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
+    </div>
+    <div class="message-content">@Message.Content</div>
+
+    @if (Message.Reactions.Count > 0)
+    {
+        <div class="message-reactions">
+            @foreach (var reaction in Message.Reactions)
+            {
+                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
+                    @reaction.Emoji @reaction.Users.Count
+                </span>
+            }
+        </div>
+    }
+
+    @if (ThreadSummary is not null)
+    {
+        <button class="thread-link btn btn-link btn-sm p-0" @onclick="OpenThread">
+            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
+        </button>
+    }
+
+    @if (_hovered)
+    {
+        <div class="message-actions">
+            <button class="btn btn-outline-secondary btn-sm" @onclick="OpenThread" title="Reply in thread">💬</button>
+            <div class="react-btn-wrapper" style="position:relative;">
+                <button class="btn btn-outline-secondary btn-sm" @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
+                <EmojiPicker Visible="_showEmojiPicker" OnEmojiSelected="HandleEmojiSelected" />
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    private bool _hovered;
+    private bool _showEmojiPicker;
+
+    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
+    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
+    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
+    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
+
+    private async Task OpenThread()
+    {
+        await OnOpenThread.InvokeAsync(Message.Id);
+    }
+
+    private void ToggleEmojiPicker()
+    {
+        _showEmojiPicker = !_showEmojiPicker;
+    }
+
+    private void OnMouseLeave()
+    {
+        _hovered = false;
+        _showEmojiPicker = false;
+    }
+
+    private async Task HandleEmojiSelected(string emoji)
+    {
+        _showEmojiPicker = false;
+        await OnReact.InvokeAsync((Message.Id, emoji));
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.Now - sentAt;
+        if (diff.TotalMinutes < 1) return "just now";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
+        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
+        return sentAt.ToString("MMM d");
+    }
+}
+

