toolArgs.file_text:
.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-item.hovered {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #6c757d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #e9ecef;
    border: 1px solid #dee2e6;
    border-radius: 12px;
    padding: 1px 8px;
    font-size: 0.8rem;
    cursor: default;
}

.thread-link {
    font-size: 0.8rem;
    margin-top: 4px;
    text-decoration: none;
    color: #0d6efd;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.message-actions .btn {
    font-size: 0.8rem;
    padding: 2px 6px;
    line-height: 1;
}

.react-btn-wrapper {
    position: relative;
}

