        <MessageArea Channel="_selectedChannel"
                     Messages="_messages"
                     ThreadSummaries="_threadSummaries"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadOlderMessages" />
    </div>

    @if (_threadOpen && _threadRoot is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRoot"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
