@code {
    private const int PageSize = 50;

    private List<Channel> _channels = [];
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];

    private bool _threadOpen;
    private Message? _threadRoot;
    private List<Message> _threadReplies = [];

    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotNetRef;
    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/Chat.razor.js");
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannel = _channels.Find(c => c.Id == channelId);
        if (_selectedChannel is null) return;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _allMessagesLoaded = _messages.Count < PageSize;
        BuildThreadSummaries();

        CloseThreadSync();
        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnread(channelId);
    }

    private async Task LoadOlderMessages()
    {
        if (_loadingMore || _allMessagesLoaded || _selectedChannel is null) return;

        _loadingMore = true;
        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _messages.Count, PageSize);
        if (older.Count < PageSize) _allMessagesLoaded = true;

        _messages.InsertRange(0, older);
        BuildThreadSummaries();
        _loadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        await RefreshMessages();
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRoot = _messages.Find(m => m.Id == rootMessageId);
        if (_threadRoot is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRoot is null || _selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(_selectedChannel.Id, content, _threadRoot.Id);
        _threadReplies.Add(reply);
        BuildThreadSummaries();
    }

    private void CloseThread() => CloseThreadSync();

    private void CloseThreadSync()
    {
        _threadOpen = false;
        _threadRoot = null;
        _threadReplies = [];
    }

    private async Task RefreshMessages()
    {
        if (_selectedChannel is null) return;
        _messages = await ChatService.GetMessagesAsync(_selectedChannel.Id, 0, _messages.Count);
        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies referencing them
        var rootIds = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
        _threadSummaries = rootIds;
    }

    private void UpdateChannelUnread(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop() => await LoadOlderMessages();

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        if (_jsModule is not null)
        {
            await _jsModule.DisposeAsync();
        }
    }
}

